insert into public.store_products
  (slug, name, category, price, image, alt, short, story, notes, featured, seo_title, seo_description)
values
  ('dahlia-bowl-set', 'Dahlia Bowl Set', 'candles', 1450, '/products/flower-bowl-set.jpg', 'Pink dahlia candle in a fluted ceramic pot with matching bud vase and oval tray', 'A wax dahlia in a fluted ceramic pot — with its own vase and tray.', '["Some people keep flowers on their desk. You keep deadlines. This is the compromise: a dahlia sculpted petal by petal in soft pink wax, set in a fluted ceramic pot you''ll keep long after the candle is gone.","It comes as a set — pot, bud vase and oval tray — so the corner of your desk becomes the one place in your day that is finished, tidy and calm."]'::jsonb, '["Hand-sculpted wax dahlia","Reusable ceramic pot, vase and tray","Made in Maputo"]'::jsonb, true, 'Dahlia Bowl Set — hand-sculpted flower candle | Soft Rituals', 'A pink wax dahlia in a fluted ceramic pot with matching vase and tray. Hand-sculpted candle, made in Maputo. Small rituals, big calm.'),
  ('flower-oval-bowl', 'Flower Oval Bowl', 'candles', 1650, '/products/flower-oval-bowl.svg', 'Large white oval bowl candle in cream wax set with six sculpted flowers — a big orange cherry blossom at the centre, pink and yellow blooms around it', 'A big oval bowl of cream wax planted with six wax flowers — an orange blossom at its heart.', '["Six flowers, one bowl, no vase to top up. A pink chrysanthemum and a bright yellow blossom sit up top, a sage-grey leaf and a wide orange cherry blossom hold the middle, and a pair of roses — one yellow, one pink — close the bottom. All of it sculpted in wax and set into a large white oval bowl of soft cream.","It''s the centrepiece for the table you keep meaning to tidy. Light a wick when the evening needs slowing down, or leave it whole as a garden that asks nothing of you."]'::jsonb, '["Six hand-sculpted wax flowers","Large white oval bowl","Orange blossom centrepiece"]'::jsonb, true, 'Flower Oval Bowl — large sculpted flower candle | Soft Rituals', 'A large white oval bowl candle set with six wax flowers around an orange cherry blossom. Hand-sculpted, made in Maputo by Soft Rituals.'),
  ('succulent-oval-bowl', 'Succulent Oval Bowl', 'candles', 1250, '/products/succulent-oval-bowl.svg', 'Small white oval bowl candle in cream wax planted with six sculpted succulents in greens and teal', 'A small oval bowl of six wax succulents. The desert garden that never needs watering.', '["A teal agave, a lime maple leaf, a ruffled echeveria, a plump dark-green cluster, a teal leaf and a tidy green rosette — six little succulents sculpted in wax and nestled into a small white oval bowl of cream.","For the windowsill that''s seen a few plants come and go. This one holds its shape through every forgotten watering, and lights one wick at a time when you want it to."]'::jsonb, '["Six sculpted wax succulents","Small white oval bowl","Greens and teal tones"]'::jsonb, false, 'Succulent Oval Bowl — small sculpted succulent candle | Soft Rituals', 'A small white oval bowl candle planted with six wax succulents in green and teal. The garden you cannot kill, handmade in Maputo.'),
  ('succulent-garden-box', 'Succulent Garden Box', 'candles', 1200, '/products/succulent-box.jpg', 'Four sculpted succulent candles planted on real pebbles in a white tray', 'Four wax succulents on real pebbles. The garden that survives you.', '["You forgot to water the last plant. And the one before that. This garden holds no grudge: a teal lotus, a green echeveria, a dark little cactus and a pale peony, sculpted in wax and planted on real pebbles.","Light one wick at a time, or keep it whole on the shelf as proof that something in your care is thriving."]'::jsonb, '["Four sculpted succulents","Set on real pebbles","Looks after itself"]'::jsonb, false, 'Succulent Garden Box — sculpted candle set | Soft Rituals', 'Four hand-sculpted succulent candles on real pebbles in a white tray. The plant you cannot kill. Handmade in Maputo by Soft Rituals.'),
  ('carved-bouquet-pillar', 'Carved Bouquet Pillar', 'candles', 950, '/products/carved-pillar.jpg', 'Soft pink pillar candle carved with roses, lilies and daisies', 'A whole bouquet carved from wax, in the softest pink.', '["Roses, lilies and daisies, carved into one soft pink pillar. It looks like something you''d be given at the end of a very good week — so give it to yourself before the week even starts.","Burn it slowly in the evenings and the flowers glow from inside. Or never burn it at all. We won''t check."]'::jsonb, '["Carved floral relief","Slow-burning pillar","Glows from within as it burns"]'::jsonb, true, 'Carved Bouquet Pillar — floral carved candle | Soft Rituals', 'A pink pillar candle carved with roses, lilies and daisies. Hand-carved, slow-burning, made in Maputo. Small rituals, big calm.'),
  ('bubble-cube', 'Bubble Cube', 'candles', 350, '/products/bubble-cube.jpg', 'Cream bubble cube candle in a kraft gift box on green paper', 'The little cream cube everyone reaches for first.', '["Small, round-shouldered and impossible not to pick up. The bubble cube is the candle equivalent of a deep breath — modest, soft, exactly enough.","Keep one by the kettle. Light it while the water boils. That''s the whole ritual, and it works."]'::jsonb, '["Fits in one hand","Cream finish","An easy first candle"]'::jsonb, false, 'Bubble Cube — small cream candle | Soft Rituals', 'A small cream bubble cube candle, handmade in Maputo. The five-minute ritual for people who work too much.'),
  ('starfish-and-shells', 'Starfish & Shells', 'candles', 350, '/products/starfish.jpg', 'Star-shaped candle with grey rim and white wax, decorated with wax seashells', 'A starfish full of wax seashells. The sea, without the traffic to Costa do Sol.', '["White wax poured into a grey starfish, finished with little shells in blue and cream. Three wicks, so the light spreads like late afternoon on the water.","For the person who keeps saying they need a beach day and keeps not taking one."]'::jsonb, '["Three wicks","Wax shell details","Sculpted starfish vessel"]'::jsonb, false, 'Starfish & Shells — seaside candle | Soft Rituals', 'A starfish-shaped candle with wax seashells and three wicks. The beach day you keep postponing, handmade in Maputo.'),
  ('ocean-in-a-glass', 'Ocean in a Glass', 'candles', 1000, '/products/ocean-glass.jpg', 'Round glass candle with deep blue gel wax, sand and shells like the sea floor', 'Deep blue gel, real sand, little shells. An aquarium that needs nothing from you.', '["Look closely: sand at the bottom, shells on the reef, and that deep clear blue that only exists in water and in this glass. It took hours to layer. It takes one match to enjoy.","Burn it at your desk and watch the light move through the blue. Closest thing to a dive you can do in a meeting."]'::jsonb, '["Layered gel wax","Real sand and shell details","Round glass vessel"]'::jsonb, false, 'Ocean in a Glass — blue gel candle | Soft Rituals', 'A deep blue gel candle layered with real sand and shells. The ocean for your desk, handmade in Maputo by Soft Rituals.'),
  ('little-buddha', 'Little Buddha', 'candles', 200, '/products/buddha.jpg', 'Soft pink Buddha candle sitting in a kraft gift box with green paper', 'A calm little figure in soft pink. He has never checked his email.', '["He sits. That''s it. That''s the skill. A small Buddha in soft pink wax, perfectly content to do absolutely nothing — which makes him the most qualified teacher in your house.","Put him where the day gets loud: next to the laptop, by the phone charger, on the kitchen counter at 18:00."]'::jsonb, '["Hand-poured figure","Soft pink wax","Boxed and gift-ready"]'::jsonb, false, 'Little Buddha — calm figure candle | Soft Rituals', 'A small pink Buddha candle, hand-poured in Maputo. A quiet teacher for loud days. Small rituals, big calm.'),
  ('iced-latte', 'Iced Latte', 'dessert-candles', 750, '/products/iced-latte.jpg', 'Iced Latte candle — creamy wax latte in a fluted glass topped with wax chocolates', 'A creamy latte topped with wax chocolates. Zero caffeine after 17:00.', '["You''ve had your last coffee of the day — your doctor, your spouse and your sleep all agree. This one is wax: a creamy latte in a fluted glass, piled with little chocolate drops.","Light it at the hour you''d normally pour another cup. Same comfort. Better night."]'::jsonb, '["Fluted glass vessel","Wax chocolate topping","The decaf that isn''t coffee at all"]'::jsonb, true, 'Iced Latte — dessert candle | Soft Rituals', 'A creamy latte candle in a fluted glass topped with wax chocolates. The after-hours coffee with zero caffeine. Handmade in Maputo.'),
  ('strawberry-matcha', 'Strawberry Matcha', 'dessert-candles', 750, '/products/strawberry-matcha.jpg', 'Strawberry Matcha candle — green wax with two wax strawberries in a frosted glass', 'Green tea and strawberries in a frosted glass. Fresh, sweet, very calm.', '["Matcha green poured over berry pink, in a frosted glass that catches the afternoon light. Two wax strawberries sit on top like they have nowhere else to be.","This is the candle for the slow hour — the one you keep promising yourself and finally taking."]'::jsonb, '["Layered green and pink wax","Frosted textured glass","Wax strawberry topping"]'::jsonb, false, 'Strawberry Matcha — dessert candle | Soft Rituals', 'A strawberry matcha candle in a frosted glass — green tea calm with wax strawberries on top. Handmade in Maputo by Soft Rituals.'),
  ('blossom', 'Blossom', 'dessert-candles', 550, '/products/blossom.jpg', 'Blossom candle — clear wax holding real dried flowers in a square glass', 'Real dried flowers held in clear wax. Spring, caught in a glass.', '["Tiny dried buds and petals, suspended in clear wax like the first week of spring decided to stay. Every Blossom is different, because every handful of flowers is.","As it burns, the light finds the petals one by one. It''s the slowest possible way to watch flowers — which is rather the point."]'::jsonb, '["Real dried flowers","Clear wax, square glass","Each one unique"]'::jsonb, false, 'Blossom — dried flower candle | Soft Rituals', 'Clear wax holding real dried flowers in a square glass. Spring in slow motion, handmade in Maputo. Small rituals, big calm.'),
  ('candy-sundae', 'Candy Sundae', 'dessert-candles', 900, '/products/sundae.jpg', 'Sundae candle piled with wax whipped cream, candies, strawberries and a waffle', 'Whipped cream, candy, strawberries, a waffle — all wax, all yours.', '["Every sweet thing you were told to stop eating, piled into one glass: whipped cream, bonbons, strawberries, a little chocolate waffle. Calories: zero. Joy: complete.","It''s the loudest thing we make, and somehow it still says relax."]'::jsonb, '["Sculpted wax toppings","Faceted glass coupe","Zero calories, all of them"]'::jsonb, false, 'Candy Sundae — dessert candle | Soft Rituals', 'A sundae candle piled with wax cream, candy and strawberries. Dessert with zero calories, handmade in Maputo by Soft Rituals.'),
  ('berry-trifle-bowl', 'Berry Trifle Bowl', 'dessert-candles', 1100, '/products/berry-bowl.jpg', 'Berry trifle candle in a crystal bowl with lid — red and gold layers with wax berries', 'A crystal bowl of wax berries with its own lid. The centrepiece that never melts in the heat.', '["Layers of red, gold and clear wax, studded with dark berries, in a proper crystal bowl with a proper crystal lid. It looks like Sunday lunch at your aunt''s house, the good one.","Three wicks under the surface. Keep the lid for when guests get curious."]'::jsonb, '["Crystal bowl with lid","Three wicks","Layered berry detail"]'::jsonb, false, 'Berry Trifle Bowl — crystal dessert candle | Soft Rituals', 'A berry trifle candle in a lidded crystal bowl with three wicks. The centrepiece that keeps, handmade in Maputo.'),
  ('berry-spritz', 'Berry Spritz', 'dessert-candles', 1000, '/products/berry-glass.jpg', 'Berry spritz candle — pink gel wax with wax berries in a gold-rimmed glass', 'A pink spritz in a gold-rimmed glass. Happy hour, no headache.', '["Pink gel poured over wax raspberries and dark cherries, in a stemmed glass with a gold rim. Hold it up to the window and it''s Friday, whatever the calendar says.","The only cocktail that improves your evening and your Monday."]'::jsonb, '["Gold-rimmed stemmed glass","Gel wax with berry details","No hangover included"]'::jsonb, false, 'Berry Spritz — cocktail candle | Soft Rituals', 'A pink cocktail candle with wax berries in a gold-rimmed glass. Happy hour without the headache, handmade in Maputo.'),
  ('tulip-trio', 'Tulip Trio', 'gift-boxes', 700, '/products/tulip-trio.jpg', 'Three tulip candles — white, red and yellow — in a kraft gift box on green paper grass', 'Three tulip candles on a bed of green. A bouquet that keeps.', '["White, red and yellow tulips on a bed of green paper grass, in a kraft box with a window. Flowers wilt by Thursday; these wait patiently for as long as you need them to.","The gift for someone who has everything except twenty quiet minutes."]'::jsonb, '["Three sculpted tulips","Kraft window box","Ready to give as-is"]'::jsonb, true, 'Tulip Trio — candle gift box | Soft Rituals', 'Three tulip candles in a windowed kraft gift box. The bouquet that doesn''t wilt, handmade in Maputo by Soft Rituals.'),
  ('hamsa-and-rose', 'Hamsa & Rose', 'gift-boxes', 650, '/products/hamsa-rose.jpg', 'Pearly hamsa hand beside a cream rose candle in a kraft gift box', 'A hand of blessings beside a cream rose, together in one box.', '["A pearly hamsa — the hand of blessings — resting beside a cream rose candle on green paper grass. Quiet protection and quiet beauty, boxed together.","For new homes, new babies, new chapters, and the people you pray for in traffic."]'::jsonb, '["Detailed hamsa","Cream rose candle","Kraft window box"]'::jsonb, false, 'Hamsa & Rose — blessing gift box | Soft Rituals', 'A hamsa hand with a cream rose candle in a kraft gift box. Quiet blessings, handmade in Maputo. Small rituals, big calm.'),
  ('cupcake-box', 'Cupcake Box', 'gift-boxes', 750, '/products/cupcake-box.jpg', 'Pink cupcake and ice-cream candles in a white gift box with pink paper', 'Cupcake and ice-cream candles in pink. The birthday cake that lasts.', '["Little cupcakes and ice-cream cones in every shade of pink, nested in a white box. It arrives looking like a patisserie window and stays looking like one.","Send it instead of cake to the friend who is ''not doing birthdays this year''. Watch them do birthdays."]'::jsonb, '["Assorted dessert candles","Pink gift presentation","Birthday-proof"]'::jsonb, false, 'Cupcake Box — dessert candle gift box | Soft Rituals', 'Cupcake and ice-cream candles in a pink gift box. The birthday cake that lasts all year, handmade in Maputo.'),
  ('organic-watermelon-soap', 'Organic Watermelon Soap', 'soaps', 250, '/products/organic-watermelon.svg', 'Illustration of the Organic Watermelon soap — red, white and green layered slice', 'Layered like the real fruit. The happiest bar in the bathroom.', '["Red, white and green, layered like a proper slice — seeds and all. It turns the two minutes at the sink into the lightest part of your day.","Made in small batches; when it sells out, we make more. Slowly."]'::jsonb, '["Layered slice design","Gentle on skin","Small batches"]'::jsonb, false, 'Organic Watermelon Soap — handmade soap | Soft Rituals', 'A layered watermelon soap — red, white and green, seeds and all. Handmade in small batches in Maputo by Soft Rituals.'),
  ('citrus-herb-soap', 'Citrus Herb Soap', 'soaps', 250, '/products/citrus-herb.svg', 'Illustration of the Citrus Herb soap — golden round bar speckled with herbs', 'Golden and clear, speckled with real herbs. Garden-clean.', '["A golden, glassy round speckled with real herbs. It smells like a garden that someone else weeds — fresh, zesty, effortless.","Best used slowly, at the end of days that went fast."]'::jsonb, '["Real herb speckles","Golden clear bar","Fresh and zesty"]'::jsonb, false, 'Citrus Herb Soap — handmade soap | Soft Rituals', 'A golden clear soap speckled with real herbs. Garden-fresh and zesty, handmade in small batches in Maputo.'),
  ('flower-garden-soaps', 'Flower Garden Soaps', 'soaps', 300, '/products/flower-garden.svg', 'Illustration of the Flower Garden soaps — daisy and blossom shaped bars', 'Daisies, roses and blossoms — a bouquet you can wash with.', '["Soaps shaped like a Sunday market bouquet: daisies, roses, little blossoms. Too pretty for the soap dish, which is exactly why they belong there.","Keep them for guests, or admit that you are also a guest in your own home and use them tonight."]'::jsonb, '["Assorted flower shapes","Gentle on skin","Guest-worthy, self-worthy"]'::jsonb, false, 'Flower Garden Soaps — handmade flower soaps | Soft Rituals', 'Flower-shaped handmade soaps — daisies, roses and blossoms. A bouquet you can wash with, made in Maputo by Soft Rituals.')
